sql:
SELECT name
FROM transformers
WHERE installation_date > '2022-02-15';

SELECT name, vector_group, sn_mva
FROM transformers
WHERE sn_mva = (SELECT MAX(sn_mva) FROM transformers);

SELECT transformer_id, MAX(warranty_expiration_date) AS latest_warranty_expiration_date
FROM transformers
GROUP BY transformer_id;

SELECT name, installation_date
FROM transformers
ORDER BY installation_date DESC;

SELECT SUM(allocated_budget) AS total_budget
FROM project_transformers
WHERE project_id = 0;

SELECT insulation_class, COUNT(*) AS transformer_count
FROM transformers
GROUP BY insulation_class;

SELECT name
FROM transformers
WHERE transformer_id IN (
  SELECT transformer_id FROM maintenance_logs
);

SELECT name, serial_number
FROM transformers
WHERE transformer_id = 1;

SELECT COUNT(DISTINCT transformer_id) 
FROM maintenance_logs 
WHERE maintenance_type = 'routine';

SELECT name
FROM transformers
WHERE warranty_expiration_date = (SELECT MAX(warranty_expiration_date) FROM transformers);
